#!/usr/bin/env python3
"""Debug the failing tests."""

import pennylane as qml
from pennylane import numpy as pnp

print("=== Debug All Trainable Arguments ===")
dev = qml.device('default.qubit', wires=3)

@qml.qnode(dev, diff_method='backprop')
def circuit(param1, param2):
    qml.RX(param1, wires=0)
    qml.RY(param2, wires=1)
    qml.CNOT(wires=[0, 1])
    return qml.expval(qml.Z(0))

param1 = pnp.array(0.1, requires_grad=True)
param2 = pnp.array(0.2, requires_grad=True)

print(f"param1 shape: {getattr(param1, 'shape', 'scalar')}")
print(f"param2 shape: {getattr(param2, 'shape', 'scalar')}")

def cost_f(p1, p2):
    return pnp.abs(circuit(p1, p2))

opt = qml.QNGOptimizer(stepsize=0.01)
mt_fn = qml.metric_tensor(circuit, approx="block-diag")

try:
    result = opt.step(cost_f, param1, param2, metric_tensor_fn=mt_fn)
    print(f"Success: {result}")
except Exception as e:
    print(f"Error: {e}")
    import traceback
    traceback.print_exc()

print("\n=== Debug No Trainable Arguments ===")
dev2 = qml.device('default.qubit', wires=3)

@qml.qnode(dev2, diff_method='backprop')
def circuit2(inputs, params):
    qml.RX(inputs[0], wires=0)
    qml.RY(params[0], wires=1)
    return qml.expval(qml.Z(0))

data = pnp.array([0.5], requires_grad=False)
params = pnp.array([0.1], requires_grad=False)  # Non-trainable!

def cost_f2(inputs, params):
    return pnp.abs(circuit2(inputs, params))

opt2 = qml.QNGOptimizer(stepsize=0.01)
mt_fn2 = qml.metric_tensor(circuit2, approx="block-diag")

try:
    result = opt2.step(cost_f2, data, params, metric_tensor_fn=mt_fn2)
    print(f"Success: {result}")
except Exception as e:
    print(f"Error: {e}")
    import traceback
    traceback.print_exc()
